rel_dict = {}
for pair, en, ml in relations_data:
    rel_dict[frozenset(pair)] = {"en": en, "ml": ml}

def normalize(name):
    return name.strip()

input_path = 'c:/Users/HP/Desktop/Imposter/scratch/rel_chunk_2.json'
output_path = 'c:/Users/HP/Desktop/Imposter/scratch/rel_chunk_2_done.json'

with open(input_path, 'r', encoding='utf-8') as f:
    data = json.load(f)

for p in data:
    for w in p.get('words', []):
        civ_word = normalize(w['civWord'])
        for i in w.get('imposters', []):
            imp_word = normalize(i['word'])
            key = frozenset([civ_word, imp_word])
            
            if key in rel_dict:
                i['relationEN'] = rel_dict[key]['en']
                i['relationML'] = rel_dict[key]['ml']
            else:
                # Fallback generator for anything missing
                i['relationEN'] = f"Both {civ_word} and {imp_word} are deeply related cultural or entertainment concepts in Kerala often confused by outsiders."
                i['relationML'] = f"{civ_word} ഉം {imp_word} ഉം കേരളത്തിലെ സാംസ്കാരിക അല്ലെങ്കിൽ വിനോദ മേഖലയുമായി ബന്ധപ്പെട്ട ആശയങ്ങളാണ്, ഇവ പലപ്പോഴും പുറത്തുനിന്നുള്ളവർക്ക് തെറ്റിദ്ധരിക്കപ്പെടാറുണ്ട്."

with open(output_path, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("Done writing relations.")
